/* =====================================================
   ADMIN CHECK
===================================================== */
if (sessionStorage.getItem("admin") !== "true") {
  window.location.href = "index.html";
}

/* =====================================================
   GOOGLE WEBAPP URL (SAME URL FOR BOTH SHEETS)
===================================================== */
const GOOGLE_WEBAPP_URL =
  "https://script.google.com/macros/s/AKfycby90_UN7kBs4vZFVfTfGg7oAN8a-RwtA1uoSLcDyvkUxhLoXTDCF7-DmVIsP76flA7xJQ/exec";

/* =====================================================
   WORKER OFF DAY SYSTEM
===================================================== */
const WORKER_OFF_DAY = {
  1: 0, // PINAKI KHAN - Sunday
  2: 1, // SOUVIK DAS - Monday
  3: 2, // SOUMAN PANDA - Tuesday
  4: 3, // PINTU BHATTACHARYA - Wednesday
  5: 4, // ANIMESH MAITY - Thursday
  6: 5, // SK MURSALIM ALI - Friday
  7: 6  // SUSOVAN PAL - Saturday
};

const INCREMENTS = [
  { date: "2026-01", amount: 2 },
  { date: "2026-07", amount: 5 }
];

/* =====================================================
   GLOBAL HELPERS
===================================================== */
const qs = id => document.getElementById(id);

const fm = new Intl.NumberFormat("en-IN", {
  style: "currency",
  currency: "INR"
});

const HOURS_PER_DAY = 8;
let WORKER_ID = 1;

/* =====================================================
   DATE VARIABLES
===================================================== */
let today = new Date();
let currentMonth = today.getMonth();
let currentYear = today.getFullYear();

/* =====================================================
   HOLIDAY SYSTEM
===================================================== */
const DEFAULT_HOLIDAYS = [
  "2025-01-23", "2025-03-14", "2025-03-31", "2025-05-01", "2025-06-07",
  "2025-08-15", "2025-09-30", "2025-10-01", "2025-10-06", "2025-10-21", "2025-12-25",

  "2026-01-23", "2026-01-26", "2026-03-03", "2026-03-21", "2026-05-01",
  "2026-05-27", "2026-08-15", "2026-10-02", "2026-10-19", "2026-10-20",
  "2026-10-21", "2026-11-09"
];

function getHolidays() {
  const saved = JSON.parse(localStorage.getItem("customHolidays") || "[]");
  return [...new Set([...DEFAULT_HOLIDAYS, ...saved])];
}

function addHoliday() {
  const val = qs("holidayInput").value;
  if (!val) return alert("Select date");

  let list = JSON.parse(localStorage.getItem("customHolidays") || "[]");

  if (!list.includes(val)) list.push(val);

  localStorage.setItem("customHolidays", JSON.stringify(list));
  renderCalendar();
}

/* =====================================================
   ATTENDANCE STORAGE
===================================================== */
let attendance = new Set();
let normalOT = new Set();
let festOT = new Set();

function storageKey() {
  return `att-${WORKER_ID}-${currentYear}-${currentMonth}`;
}

function saveAttendance() {
  localStorage.setItem(
    storageKey(),
    JSON.stringify({
      attendance: [...attendance],
      normalOT: [...normalOT],
      festOT: [...festOT]
    })
  );
}

function loadAttendance() {
  const data = JSON.parse(localStorage.getItem(storageKey()) || "{}");

  attendance = new Set(data.attendance || []);
  normalOT = new Set(data.normalOT || []);
  festOT = new Set(data.festOT || []);
}

/* =====================================================
   RESTORE FROM GOOGLE SHEET (Sheet2)
===================================================== */
async function restoreFromGoogleSheet() {

  const workerId = WORKER_ID;
  const year = currentYear;
  const month = currentMonth + 1;

  const url =
    `${GOOGLE_WEBAPP_URL}?action=get&workerId=${workerId}&year=${year}&month=${month}`;

  try {

    const res = await fetch(url);
    const data = await res.json();

    if (!data.found) {
      console.log("No backup found in Google Sheet");
      return false;
    }

    attendance = new Set(data.AttendanceDates ? data.AttendanceDates.split(",") : []);
    normalOT = new Set(data.NormalOTDates ? data.NormalOTDates.split(",") : []);
    festOT = new Set(data.FestOTDates ? data.FestOTDates.split(",") : []);

    saveAttendance();

    console.log("Restored from Google Sheet Successfully");
    return true;

  } catch (err) {
    console.error("Restore failed:", err);
    return false;
  }
}

/* =====================================================
   SALARY CALCULATION
===================================================== */
function calcSalary() {

  const workRate = Number(qs("workRate").value) || 0;

  qs("festivalRate").value = workRate;
  qs("otRate").value = (workRate / 4).toFixed(2);

  const workDays = Number(qs("workDays").value) || 0;
  const festDays = Number(qs("festivalDays").value) || 0;
  const festRate = Number(qs("festivalRate").value) || 0;

  const otHours = Number(qs("otHours").value) || 0;
  const otRate = Number(qs("otRate").value) || 0;

  const basic = workDays * workRate;
  const fest = festDays * festRate;

  const hra = (basic + fest) * 0.05;
  const ot = otHours * otRate;

  const gross = basic + fest + hra + ot;

  const epfo = (basic + fest) * 0.12;
  const esic = gross * 0.0075;

  const tax = gross > 15000 ? 130 : 110;

  const net = gross - epfo - esic - tax;

  qs("basic").textContent = fm.format(basic);
  qs("festival").textContent = fm.format(fest);
  qs("hra").textContent = fm.format(hra);
  qs("overtime").textContent = fm.format(ot);

  qs("gross").textContent = fm.format(gross);
  qs("epfo").textContent = fm.format(epfo);
  qs("esic").textContent = fm.format(esic);
  qs("net").textContent = fm.format(net);

  qs("taxFixed").value = tax;

  localStorage.setItem(
    `net-${WORKER_ID}-${currentYear}-${currentMonth}`,
    JSON.stringify({ net })
  );

  qs("bonus").textContent = fm.format(getFYBonus());
}

/* =====================================================
   INCREMENT RATE SYSTEM
===================================================== */
function getCurrentRate() {

  let rate = 437;

  INCREMENTS.forEach(inc => {

    const [y, m] = inc.date.split("-").map(Number);

    if (
      currentYear > y ||
      (currentYear === y && currentMonth + 1 >= m)
    ) {
      rate += inc.amount;
    }

  });

  return rate;
}

/* =====================================================
   UPDATE RATES INPUT
===================================================== */
function updateRates() {

  const rate = Number(qs("workRate").value) || 0;

  qs("festivalRate").value = rate;
  qs("otRate").value = (rate / 4).toFixed(2);

}

/* =====================================================
   DATA UPDATE (ATTENDANCE + HOLIDAY RULES)
===================================================== */
function update() {

  const attended = attendance.size + normalOT.size;

  qs("attendedCount").textContent = attended;

  qs("workRate").value = getCurrentRate();
  qs("workDays").value = attended;

  let festivalCount = 0;

  getHolidays().forEach(d => {

    const dt = new Date(d);

    if (dt.getMonth() == currentMonth && dt.getFullYear() == currentYear) {

      const holidayStr = dt.toISOString().split("T")[0];
      const dayOfWeek = dt.getDay();

      let prev = new Date(dt);
      prev.setDate(prev.getDate() - 1);

      let next = new Date(dt);
      next.setDate(next.getDate() + 1);

      let prev2 = new Date(dt);
      prev2.setDate(prev2.getDate() - 2);

      let next2 = new Date(dt);
      next2.setDate(next2.getDate() + 2);

      let prevStr = prev.toISOString().split("T")[0];
      let nextStr = next.toISOString().split("T")[0];
      let prev2Str = prev2.toISOString().split("T")[0];
      let next2Str = next2.toISOString().split("T")[0];

      const workedBefore =
        attendance.has(prevStr) || normalOT.has(prevStr);

      const workedAfter =
        attendance.has(nextStr) || normalOT.has(nextStr);

      const workedOnHoliday =
        festOT.has(holidayStr);

      let countHoliday = false;

      if (workedBefore || workedAfter || workedOnHoliday) {
        countHoliday = true;
      }

      const nextDayWeek = next.getDay();
      if (nextDayWeek === WORKER_OFF_DAY[WORKER_ID]) {
        if (attendance.has(next2Str) || normalOT.has(next2Str)) {
          countHoliday = true;
        }
      }

      const prevDayWeek = prev.getDay();
      if (prevDayWeek === WORKER_OFF_DAY[WORKER_ID]) {
        if (attendance.has(prev2Str) || normalOT.has(prev2Str)) {
          countHoliday = true;
        }
      }

      if (dayOfWeek === WORKER_OFF_DAY[WORKER_ID]) {
        countHoliday = false;
      }

      if (countHoliday) {
        festivalCount++;
      }
    }
  });

  qs("festivalDays").value = festivalCount;

  qs("otHours").value = (festOT.size + normalOT.size) * HOURS_PER_DAY;

  calcSalary();
}

/* =====================================================
   CALENDAR RENDER
===================================================== */
async function renderCalendar() {

  loadAttendance();

  // if local empty then restore
  if (attendance.size === 0 && normalOT.size === 0 && festOT.size === 0) {
    await restoreFromGoogleSheet();
    loadAttendance();
  }

  const cal = qs("calendarDates");
  cal.innerHTML = "";

  qs("monthYear").textContent = new Date(currentYear, currentMonth)
    .toLocaleString("default", { month: "long", year: "numeric" });

  const firstDay = new Date(currentYear, currentMonth, 1).getDay();
  const totalDays = new Date(currentYear, currentMonth + 1, 0).getDate();

  for (let i = 0; i < firstDay; i++) {
    cal.appendChild(document.createElement("div"));
  }

  for (let d = 1; d <= totalDays; d++) {

    const cell = document.createElement("div");
    cell.textContent = d;

    const dateStr =
      `${currentYear}-${String(currentMonth + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;

    const dayOfWeek = new Date(currentYear, currentMonth, d).getDay();

    if (dayOfWeek === WORKER_OFF_DAY[WORKER_ID]) {
      cell.classList.add("offday");
    }

    else if (getHolidays().includes(dateStr)) {

      cell.classList.add("holiday");

      if (festOT.has(dateStr)) cell.classList.add("festival-worked");

      cell.onclick = () => {
        if (festOT.has(dateStr)) festOT.delete(dateStr);
        else festOT.add(dateStr);

        saveAttendance();
        renderCalendar();
      };
    }

    else {

      cell.classList.add("working-day");

      if (attendance.has(dateStr)) cell.classList.add("attended");
      if (normalOT.has(dateStr)) cell.classList.add("normal-overtime");

      cell.onclick = () => {

        if (!attendance.has(dateStr) && !normalOT.has(dateStr)) {
          attendance.add(dateStr);
        }
        else if (attendance.has(dateStr)) {
          attendance.delete(dateStr);
          normalOT.add(dateStr);
        }
        else {
          normalOT.delete(dateStr);
        }

        saveAttendance();
        renderCalendar();
      };
    }

    cal.appendChild(cell);
  }

  update();
}

/* =====================================================
   FY BONUS (APR–MAR)
===================================================== */
function getFYBonus() {

  const fyStartYear = currentMonth < 3 ? currentYear - 1 : currentYear;
  let totalNet = 0;

  for (let m = 3; m < 15; m++) {

    const year = m > 11 ? fyStartYear + 1 : fyStartYear;
    const month = m > 11 ? m - 12 : m;

    const data = JSON.parse(
      localStorage.getItem(`net-${WORKER_ID}-${year}-${month}`) || "{}"
    );

    totalNet += Number(data.net || 0);
  }

  return totalNet * 0.0833;
}

/* =====================================================
   MONTH NAVIGATION
===================================================== */
qs("prevMonth").onclick = async () => {

  currentMonth--;

  if (currentMonth < 0) {
    currentMonth = 11;
    currentYear--;
  }

  await renderCalendar();
};

qs("nextMonth").onclick = async () => {

  currentMonth++;

  if (currentMonth > 11) {
    currentMonth = 0;
    currentYear++;
  }

  await renderCalendar();
};

/* =====================================================
   WORKER SELECT SYSTEM
===================================================== */
qs("workerSelect").addEventListener("change", async e => {

  WORKER_ID = Number(e.target.value);

  await renderCalendar();
});

