/* =====================================================
   ALL WORKERS PDF REPORT
===================================================== */
async function downloadAllWorkersPDF() {

  const { jsPDF } = window.jspdf;

  const pdf = new jsPDF("p", "mm", "a4");

  let workerCount = 0;

  for (let i = 1; i <= 7; i++) {

    qs("workerSelect").value = i
    WORKER_ID = i

    renderCalendar();

    await new Promise(r => setTimeout(r, 100))

    const container = document.createElement("div")
    container.innerHTML = getSalarySlipHTML()

    document.body.appendChild(container)

    const canvas = await html2canvas(container)

    const img = canvas.toDataURL("image/png")

    let yPosition = workerCount % 2 === 0 ? 10 : 150

    pdf.addImage(img, "PNG", 10, yPosition, 190, 130)

    workerCount++

    if (workerCount % 2 === 0 && i !== 7) {
      pdf.addPage()
    }

    container.remove()

  }

  pdf.save("7_Workers_Salary_Report.pdf")

}

